// WF_DISCOVER_COMPETITORS — Validate payload, auth check, fetch source channel.

const raw = $input.first().json;
const payload = raw.body || raw;
const headers = raw.headers || {};

// Auth check
const expectedToken = $env.DASHBOARD_API_TOKEN;
const authHeader = headers.authorization || headers.Authorization || '';
if (!authHeader || authHeader !== `Bearer ${expectedToken}`) {
  return [{ json: { success: false, error: 'Unauthorized', http_status: 401 } }];
}

const analysisGroupId = (payload.analysis_group_id || '').trim();
const sourceChannelAnalysisId = (payload.source_channel_analysis_id || '').trim();

if (!analysisGroupId || !sourceChannelAnalysisId) {
  return [{ json: { success: false, error: 'analysis_group_id and source_channel_analysis_id are required', http_status: 400 } }];
}

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

// Fetch source channel analysis
try {
  const srcRes = await fetch(
    `${supabaseUrl}/rest/v1/channel_analyses?id=eq.${sourceChannelAnalysisId}&select=id,youtube_channel_id,channel_name,primary_topics,top_videos,status,analysis_group_id`,
    { method: 'GET', headers: sbHeaders }
  );
  if (!srcRes.ok) {
    return [{ json: { success: false, error: `Supabase fetch failed: HTTP ${srcRes.status}`, http_status: 500 } }];
  }
  const rows = await srcRes.json();
  const src = Array.isArray(rows) && rows[0] ? rows[0] : null;

  if (!src) {
    return [{ json: { success: false, error: 'Source channel analysis not found', http_status: 404 } }];
  }
  if (src.status !== 'completed') {
    return [{ json: { success: false, error: `Source analysis not completed (status: ${src.status})`, http_status: 409 } }];
  }

  return [{ json: {
    success: true,
    analysis_group_id: analysisGroupId,
    source_channel_analysis_id: sourceChannelAnalysisId,
    source_channel_id: src.youtube_channel_id,
    source_channel_name: src.channel_name,
    primary_topics: src.primary_topics || [],
    top_videos: src.top_videos || [],
    http_status: 202
  } }];
} catch (e) {
  return [{ json: { success: false, error: `Exception: ${e.message}`, http_status: 500 } }];
}

// Gate: only continue if validation succeeded.
const data = $input.first().json;
if (!data.success) {
  return []; // empty = stop execution on this branch
}
return [{ json: data }];

// Build 5 YouTube search queries from source channel's topics and top video tags.

const data = $input.first().json;
const primaryTopics = data.primary_topics || [];
const topVideos = data.top_videos || [];
const sourceChannelName = data.source_channel_name || '';
const sourceChannelId = data.source_channel_id || '';

const queries = [];

// Query 1: main topic + "youtube channel"
if (primaryTopics.length > 0) {
  queries.push(primaryTopics[0] + ' youtube channel');
}

// Query 2-3: secondary topics (pick the 2nd and 3rd if available)
if (primaryTopics.length > 1) {
  queries.push(primaryTopics[1]);
}
if (primaryTopics.length > 2) {
  queries.push(primaryTopics[2]);
}

// Query 4: tags from top 3 videos combined (use top video titles as proxy)
if (topVideos.length > 0) {
  const titleWords = topVideos.slice(0, 3)
    .map(v => (v.title || '').replace(/[^a-zA-Z0-9\s]/g, '').trim())
    .join(' ');
  // Extract most significant words (longer than 4 chars, deduplicate)
  const words = titleWords.split(/\s+/)
    .filter(w => w.length > 4)
    .map(w => w.toLowerCase());
  const unique = [...new Set(words)].slice(0, 5);
  if (unique.length > 0) {
    queries.push(unique.join(' '));
  }
}

// Query 5: channel name + "similar channels"
if (sourceChannelName) {
  queries.push(sourceChannelName + ' similar channels');
}

// Ensure at least 1 query
if (queries.length === 0 && primaryTopics.length > 0) {
  queries.push(primaryTopics.join(' '));
}
if (queries.length === 0) {
  queries.push(sourceChannelName || 'youtube channel');
}

// Limit to 5 queries max
const finalQueries = queries.slice(0, 5);

return [{ json: {
  ...data,
  search_queries: finalQueries,
  exclude_channel_id: sourceChannelId
} }];

// Search YouTube for competing channels, deduplicate, fetch stats, filter & rank top 10.

const data = $input.first().json;
const queries = data.search_queries || [];
const excludeChannelId = data.exclude_channel_id || '';
const ytKey = $env.YOUTUBE_API_KEY;

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

const sleep = (ms) => new Promise(r => setTimeout(r, ms));

async function fetchWithRetry(url, options, label, maxRetries = 4) {
  let lastErr = null;
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const res = await fetch(url, options);
      if (res.ok) return { ok: true, json: await res.json(), status: res.status, attempts: attempt };
      const body = await res.text();
      if (res.status === 403 && /quotaExceeded|dailyLimitExceeded/i.test(body)) {
        return { ok: false, quota: true, status: res.status, error: body, attempts: attempt };
      }
      if (res.status >= 400 && res.status < 500 && res.status !== 429) {
        return { ok: false, status: res.status, error: body, attempts: attempt };
      }
      lastErr = new Error(`HTTP ${res.status}: ${body.slice(0, 300)}`);
    } catch (e) { lastErr = e; }
    if (attempt < maxRetries) await sleep(Math.min(1000 * Math.pow(2, attempt - 1), 30000));
  }
  return { ok: false, status: 0, error: lastErr?.message || `${label} failed`, attempts: maxRetries };
}

// Step 1: Search for channels across all queries
const discoveredMap = new Map(); // channelId -> { snippet, queryIndex, discoveryMethod }

for (let qi = 0; qi < queries.length; qi++) {
  const query = queries[qi];
  const searchUrl = `https://www.googleapis.com/youtube/v3/search?part=snippet&type=channel&q=${encodeURIComponent(query)}&maxResults=10&order=relevance&key=${ytKey}`;
  const searchRes = await fetchWithRetry(searchUrl, { method: 'GET' }, `yt_search_q${qi}`);

  if (searchRes.quota) {
    // Log quota error but continue with what we have
    break;
  }
  if (searchRes.ok) {
    const items = searchRes.json?.items || [];
    for (const item of items) {
      const chId = item.snippet?.channelId || item.id?.channelId;
      if (!chId || chId === excludeChannelId) continue;
      if (!discoveredMap.has(chId)) {
        const method = qi === 0 ? 'keyword_search' : qi <= 2 ? 'keyword_search' : qi === 3 ? 'tag_match' : 'related_channels';
        discoveredMap.set(chId, {
          channel_id: chId,
          channel_name: item.snippet?.title || 'Unknown',
          channel_handle: item.snippet?.customUrl || null,
          description: (item.snippet?.description || '').slice(0, 500),
          discovery_method: method,
          query_index: qi
        });
      }
    }
  }
  // Rate limit: 200ms between API calls
  await sleep(200);
}

// Step 2: Fetch detailed stats for top 20 unique channels (batched)
const channelIds = [...discoveredMap.keys()].slice(0, 20);
const enrichedChannels = [];

if (channelIds.length > 0) {
  // YouTube channels API supports up to 50 IDs per call
  const statsUrl = `https://www.googleapis.com/youtube/v3/channels?part=statistics,snippet&id=${channelIds.join(',')}&key=${ytKey}`;
  const statsRes = await fetchWithRetry(statsUrl, { method: 'GET' }, 'yt_channel_stats');

  if (statsRes.ok) {
    const items = statsRes.json?.items || [];
    for (const ch of items) {
      const stats = ch.statistics || {};
      const snippet = ch.snippet || {};
      const subCount = parseInt(stats.subscriberCount || '0', 10);
      const viewCount = parseInt(stats.viewCount || '0', 10);
      const vidCount = parseInt(stats.videoCount || '0', 10);

      // Filter: skip channels with fewer than 5 videos (dead channels)
      if (vidCount < 5) continue;

      const disc = discoveredMap.get(ch.id);
      const avgViews = vidCount > 0 ? Math.round(viewCount / vidCount) : 0;

      enrichedChannels.push({
        youtube_channel_id: ch.id,
        channel_name: snippet.title || disc?.channel_name || 'Unknown',
        channel_url: snippet.customUrl
          ? `https://www.youtube.com/${snippet.customUrl}`
          : `https://www.youtube.com/channel/${ch.id}`,
        channel_handle: snippet.customUrl || disc?.channel_handle || null,
        subscriber_count: subCount,
        total_view_count: viewCount,
        video_count: vidCount,
        avg_views_per_video: avgViews,
        discovery_method: disc?.discovery_method || 'keyword_search',
        // Relevance: weighted mix of subscribers (40%) + avg views (40%) + video count (20%)
        _sub_score: subCount,
        _view_score: avgViews,
        _vid_score: vidCount
      });
    }
  }
}

// Step 3: Sort by relevance and take top 10
if (enrichedChannels.length > 0) {
  // Normalize each factor to 0-100 relative to the set
  const maxSub = Math.max(...enrichedChannels.map(c => c._sub_score), 1);
  const maxView = Math.max(...enrichedChannels.map(c => c._view_score), 1);
  const maxVid = Math.max(...enrichedChannels.map(c => c._vid_score), 1);

  for (const ch of enrichedChannels) {
    ch.relevance_score = Math.round(
      (ch._sub_score / maxSub) * 40 +
      (ch._view_score / maxView) * 40 +
      (ch._vid_score / maxVid) * 20
    );
    // Clamp to [0, 100]
    ch.relevance_score = Math.max(0, Math.min(100, ch.relevance_score));
    delete ch._sub_score;
    delete ch._view_score;
    delete ch._vid_score;
  }

  enrichedChannels.sort((a, b) => b.relevance_score - a.relevance_score);
}

const top10 = enrichedChannels.slice(0, 10);

// Assign discovery_rank
top10.forEach((ch, i) => {
  ch.discovery_rank = i + 1;
});

return [{ json: {
  ...data,
  discovered_channels: top10,
  total_candidates_found: discoveredMap.size,
  total_after_filter: enrichedChannels.length,
  failed: false
} }];

// Insert discovered channels into Supabase with ON CONFLICT idempotency.

const data = $input.first().json;
if (data.failed) return [{ json: data }];

const channels = data.discovered_channels || [];
const analysisGroupId = data.analysis_group_id;
const sourceAnalysisId = data.source_channel_analysis_id;

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

let insertedCount = 0;
let errorCount = 0;

for (const ch of channels) {
  const row = {
    analysis_group_id: analysisGroupId,
    source_channel_analysis_id: sourceAnalysisId,
    youtube_channel_id: ch.youtube_channel_id,
    channel_name: ch.channel_name,
    channel_url: ch.channel_url,
    channel_handle: ch.channel_handle,
    subscriber_count: ch.subscriber_count,
    total_view_count: ch.total_view_count,
    video_count: ch.video_count,
    avg_views_per_video: ch.avg_views_per_video,
    discovery_method: ch.discovery_method,
    discovery_rank: ch.discovery_rank,
    relevance_score: ch.relevance_score,
    analysis_depth: 'quick',
    analysis_status: 'discovered'
  };

  try {
    // Use Prefer: resolution=merge-duplicates for ON CONFLICT DO NOTHING behavior
    const res = await fetch(`${supabaseUrl}/rest/v1/discovered_channels`, {
      method: 'POST',
      headers: {
        ...sbHeaders,
        'Prefer': 'return=minimal,resolution=ignore-duplicates'
      },
      body: JSON.stringify(row)
    });
    if (res.ok || res.status === 201 || res.status === 200) {
      insertedCount++;
    } else {
      const errText = await res.text();
      // 409 = conflict (already exists) — that's fine, count as success
      if (res.status === 409) {
        insertedCount++;
      } else {
        errorCount++;
      }
    }
  } catch (e) {
    errorCount++;
  }
}

return [{ json: {
  ...data,
  inserted_count: insertedCount,
  error_count: errorCount,
  failed: false
} }];

// Calculate aggregate stats for discovered channels.

const data = $input.first().json;
if (data.failed) return [{ json: data }];

const channels = data.discovered_channels || [];

const totalSubscribers = channels.reduce((s, c) => s + (c.subscriber_count || 0), 0);
const totalViews = channels.reduce((s, c) => s + (c.total_view_count || 0), 0);
const avgViewsArr = channels.map(c => c.avg_views_per_video || 0).filter(v => v > 0);
const avgViewsPerVideo = avgViewsArr.length
  ? Math.round(avgViewsArr.reduce((a, b) => a + b, 0) / avgViewsArr.length)
  : 0;

// Niche size estimate based on total subscribers across top competitors
let nicheSizeEstimate = 'small';
if (totalSubscribers >= 10_000_000) nicheSizeEstimate = 'very_large';
else if (totalSubscribers >= 3_000_000) nicheSizeEstimate = 'large';
else if (totalSubscribers >= 500_000) nicheSizeEstimate = 'medium';

const summary = {
  total_subscribers: totalSubscribers,
  total_views: totalViews,
  avg_views_per_video: avgViewsPerVideo,
  niche_size_estimate: nicheSizeEstimate,
  channels_discovered: channels.length,
  top_channel: channels.length > 0 ? channels[0].channel_name : null,
  top_channel_subs: channels.length > 0 ? channels[0].subscriber_count : 0
};

return [{ json: {
  ...data,
  discovery_summary: summary,
  failed: false
} }];

// Log discovery completion to production_logs.

const data = $input.first().json;
const summary = data.discovery_summary || {};

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

try {
  await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
    method: 'POST',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify({
      project_id: null,
      topic_id: null,
      stage: 'discover_competitors',
      scene_number: null,
      action: 'discovery_completed',
      status: 'success',
      duration_ms: 0,
      cost_usd: 0,
      retry_count: 0,
      details: JSON.stringify({
        analysis_group_id: data.analysis_group_id,
        source_channel: data.source_channel_name,
        channels_discovered: summary.channels_discovered || 0,
        total_subscribers: summary.total_subscribers || 0,
        niche_size_estimate: summary.niche_size_estimate || 'unknown',
        total_candidates_found: data.total_candidates_found || 0,
        total_after_filter: data.total_after_filter || 0
      })
    })
  });
} catch (_) {}

return [{ json: {
  success: true,
  analysis_group_id: data.analysis_group_id,
  channels_discovered: summary.channels_discovered || 0,
  niche_size_estimate: summary.niche_size_estimate || 'unknown',
  discovery_summary: summary
} }];
